final:
module top_module (
    input a,
    input b,
    input c,
    input d,
    output reg not_out
);    always @(*) begin
        case ({a, b, c, d})
            4'b0000: not_out = 1'b1;
            4'b0001: not_out = 1'b1;
            4'b0010: not_out = 1'b0;
            4'b0011: not_out = 1'b0;
            4'b0100: not_out = 1'b0;
            4'b0101: not_out = 1'b0;
            4'b0110: not_out = 1'b0;
            4'b0111: not_out = 1'b0;
            4'b1000: not_out = 1'b1;
            4'b1001: not_out = 1'b1;
            4'b1010: not_out = 1'b0;
            4'b1011: not_out = 1'b1;
            4'b1100: not_out = 1'b0;
            4'b1101: not_out = 1'b0;
            4'b1110: not_out = 1'b0;
            4'b1111: not_out = 1'b1;
        endcase
    end
endmodule
